      printf("Usage: %s [PREFIX]\n", argv[0]);
      return -1;
    } else {
      strncpy(pref, argv[1], sizeof(pref));
      pref[sizeof(pref) - 1] = 0;
    }
    while (1) {
      for (int i = 0; i < 20; i++) {
        buff[i] = ascii[rand() % strlen(ascii)];
      }
      buff[20] = 0;
      if (checkwith(buff, pref)) {
        puts(buff);
        return 0;
      }
