    case LDW_RULE_MODE_UNCOND:
      has_name = 0;
      break;
    case LDW_RULE_MODE_PREFIX...LDW_RULE_MODE_SUFFIX:
      if (!name_len)
        return -EINVAL;
      break;
    default:
      return -EINVAL;
